#include<bits/stdc++.h>
using namespace std;
char s[200010];
int sumo[200010],sumw[200010],sumc[200010];
int main()
{
	scanf("%s",s+1);
	int n=strlen(s+1);
	for(int i=1;i<=n;i++)
	{
		sumo[i]=sumo[i-1];
		sumw[i]=sumw[i-1];
		sumc[i]=sumc[i-1];
		if(s[i]=='O')
		{
			sumo[i]++;
		}
		else if(s[i]=='W')
		{
			sumw[i]++;
		}
		else
		{
			sumc[i]++;
		}
	}
	int q;
	scanf("%d",&q);
	while(q--)
	{
		int l,r;
		scanf("%d%d",&l,&r);
		int c=sumc[r]-sumc[l-1];
		int o=sumo[r]-sumo[l-1];
		int w=sumw[r]-sumw[l-1];
		if(o%2==w%2&&c%2!=o%2)
		{
			printf("Y");
		}
		else
		{
			
			printf("N");
		}
	}
	return 0;
}
